example.code:
# Registry module — pessimistic constraint (recommended)
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"      # >= 5.0.0, < 6.0.0
}

# Registry module — explicit range
module "s3" {
  source  = "terraform-aws-modules/s3-bucket/aws"
  version = ">= 4.0, < 5.0"
}

# GitHub module — pinned to exact tag (acceptable for external repos)
module "network" {
  source = "github.com/org/terraform-modules//network?ref=v1.2.3"
}

# Local module — no version argument
module "ecs" {
  source = "./modules/ecs"
}

# No version argument — fetches latest on every terraform init
module "vpc" {
  source = "terraform-aws-modules/vpc/aws"
}
